def add(instruction, output):
    data.append({"instruction": instruction, "input": "", "output": output})

# 1. אבטחת מידע
add("מהי אבטחת מידע (Information Security)?",
"אבטחת מידע היא תחום העוסק בהגנה על מידע ומערכות מידע מפני גישה, שימוש, חשיפה, שיבוש, שינוי או השמדה בלתי מורשים. המטרה המרכזית מתומצתת במודל CIA Triad: Confidentiality (סודיות - רק גורמים מורשים ניגשים למידע), Integrity (שלמות - המידע לא משתנה ללא הרשאה ואפשר לזהות שינוי אם קרה) ו-Availability (זמינות - המערכת והמידע זמינים למשתמשים מורשים כשצריך). אבטחת מידע כוללת היבטים טכניים (הצפנה, חומות אש, בקרת גישה), ארגוניים (מדיניות, נהלים, הדרכת עובדים) ומשפטיים (עמידה ברגולציה כמו GDPR).")
add("מהם שלושת עמודי התווך של אבטחת מידע (CIA Triad)?",
"CIA Triad מורכב משלושה עקרונות: 1) Confidentiality (סודיות) - מניעת חשיפת מידע לגורמים לא מורשים, נאכפת באמצעות הצפנה ובקרת גישה. 2) Integrity (שלמות) - הבטחה שהמידע מדויק ולא שונה ללא הרשאה, נאכפת באמצעות hashing, חתימות דיגיטליות וביקורת. 3) Availability (זמינות) - הבטחה שהמערכות והנתונים נגישים כשנדרש, נאכפת באמצעות redundancy, גיבויים והגנה מפני מתקפות DDoS. כל החלטת אבטחה שוקלת איזון בין שלושת המרכיבים הללו.")

# 2. Ethical Hacking
add("מהו Ethical Hacking (האקינג אתי)?",
"Ethical Hacking הוא תהליך שבו איש מקצוע מורשה (Penetration Tester / White Hat Hacker) מדמה מתקפות סייבר על מערכת, רשת או אפליקציה, במטרה לאתר חולשות אבטחה לפני שתוקפים זדוניים ינצלו אותן. הפעולה מתבצעת בהסכמה מפורשת של הבעלים (Scope מוגדר, הסכם Rules of Engagement), ומסתיימת בדוח מפורט הכולל ממצאים, רמת סיכון והמלצות לתיקון. שלבים אופייניים: Reconnaissance, Scanning, Gaining Access, Maintaining Access, ולבסוף Reporting וניקוי עקבות.")
add("מה ההבדל בין White Hat, Black Hat ו-Gray Hat Hacker?",
"White Hat - האקר אתי הפועל בהרשאה חוקית כדי לשפר אבטחה. Black Hat - תוקף זדוני הפורץ למערכות ללא הרשאה לצורך רווח, נזק או ריגול. Gray Hat - פועל ללא הרשאה מפורשת אך לרוב ללא כוונה זדונית, ולעיתים מדווח על חולשות שמצא (למשל דרך תוכניות Bug Bounty), אך עדיין עלול לעבור על החוק בכך שפעל ללא אישור מראש.")

# 3. רשתות
add("מהי רשת מחשבים (Networking) ומהם המושגים הבסיסיים בה?",
"רשת מחשבים היא קבוצת מכשירים המחוברים זה לזה לצורך שיתוף משאבים ותקשורת. מושגי יסוד: Node/Host (מכשיר ברשת), IP Address (כתובת לוגית ייחודית למכשיר), MAC Address (כתובת פיזית של כרטיס הרשת), Router (מנתב תעבורה בין רשתות), Switch (מחבר מכשירים ברשת מקומית), Firewall (חוסם/מסנן תעבורה לפי כללים), Subnet (חלוקה לוגית של רשת), ו-Port (נקודת קצה לוגית לזיהוי שירות/תהליך על גבי מכשיר).")
add("מהם מודל OSI ומודל TCP/IP ומה תפקידם?",
"מודל OSI הוא מודל תיאורטי בן 7 שכבות (Physical, Data Link, Network, Transport, Session, Presentation, Application) המתאר כיצד מידע עובר ברשת. מודל TCP/IP הוא מודל מעשי בן 4 שכבות (Network Access, Internet, Transport, Application) שעליו מבוסס האינטרנט בפועל. הבנת השכבות חשובה לאבטחה כי כל שכבה חשופה לסוגי מתקפות שונים - למשל ARP Spoofing בשכבת Data Link, IP Spoofing בשכבת Network ו-SQL Injection בשכבת Application.")

# 4. Linux
add("למה Linux חשוב כל כך בתחום אבטחת המידע?",
"Linux הוא מערכת ההפעלה הדומיננטית בשרתים, בענן ובכלי אבטחה (למשל Kali Linux). חשיבותו נובעת מהיותה קוד פתוח (שקיפות מלאה), גמישות גבוהה (Shell scripting, אוטומציה), מודל הרשאות חזק (Users, Groups, Permissions בסגנון rwx), וכלים מובנים לניתוח וניטור (grep, netstat, iptables, systemd journal). האקרים אתיים ואנשי SOC משתמשים ב-Linux הן כפלטפורמת תקיפה (Kali/Parrot OS) והן כמערכת שיש להגן עליה בסביבות שרתים.")
add("מהם עקרונות ניהול ההרשאות ב-Linux (Permissions)?",
"בלינוקס לכל קובץ ותיקייה יש שלוש קבוצות הרשאה: Owner, Group, Others, וכל קבוצה מקבלת שילוב של r (read), w (write), x (execute), המיוצג בפקודת ls -l כמו rwxr-xr--. פקודת chmod משנה הרשאות (למשל chmod 750), chown משנה בעלים. הרשאות שגויות (למשל 777 על קובץ רגיש) הן חולשת אבטחה נפוצה. כמו כן קיים מנגנון SUID/SGID המאפשר הרצת תוכנית בהרשאות הבעלים - ניצול לרעה שלו הוא וקטור נפוץ ל-Privilege Escalation.")

# 5. HTTP
add("מהו פרוטוקול HTTP וכיצד הוא עובד?",
"HTTP (HyperText Transfer Protocol) הוא פרוטוקול שכבת האפליקציה המשמש לתקשורת בין דפדפן (Client) לשרת web. עובד במודל Request-Response: הלקוח שולח בקשה עם Method (GET, POST, PUT, DELETE וכו'), Headers ולעיתים Body, והשרת מחזיר Status Code (למשל 200 OK, 404 Not Found, 500 Internal Server Error) יחד עם Headers ו-Body. HTTP הוא Stateless - כל בקשה עצמאית ואינה 'זוכרת' בקשות קודמות, ולכן נדרשים מנגנונים כמו Cookies ו-Sessions לשמירת מצב.")
add("מה ההבדל בין HTTP ל-HTTPS?",
"HTTPS הוא HTTP הרץ מעל שכבת הצפנה TLS/SSL. בעוד HTTP שולח נתונים כטקסט גלוי (חשוף להאזנה - Man-in-the-Middle), HTTPS מצפין את כל התעבורה בין הלקוח לשרת, מבטיח שלמות נתונים ומאמת את זהות השרת באמצעות תעודת SSL/TLS שהונפקה על ידי גורם מאמת (CA). כיום כמעט כל אתר מחויב להשתמש ב-HTTPS, ודפדפנים מסמנים אתרי HTTP כ'לא מאובטחים'.")

# 6. DNS
add("מהו DNS וכיצד הוא פועל?",
"DNS (Domain Name System) הוא מערכת המתרגמת שמות דומיין קריאים לבני אדם (כמו example.com) לכתובות IP שמחשבים משתמשים בהן. התהליך: הלקוח שולח שאילתה לשרת DNS Resolver, שפונה בהיררכיה לשרתי Root, TLD (כמו .com) ולבסוף לשרת ה-Authoritative Name Server של הדומיין, שמחזיר את כתובת ה-IP. תוצאות נשמרות ב-Cache לזמן מוגבל (TTL) לשיפור ביצועים.")
add("מהן מתקפות אבטחה נפוצות הקשורות ל-DNS?",
"מתקפות DNS נפוצות כוללות: DNS Spoofing/Cache Poisoning - הזרקת רשומות DNS מזויפות לזיכרון המטמון כדי להפנות משתמשים לאתר זדוני; DNS Tunneling - שימוש בשאילתות DNS להברחת נתונים או תקשורת פקודה-ובקרה (C2) דרך חומות אש; DNS Hijacking - השתלטות על הגדרות DNS של דומיין או ראוטר; ו-DDoS דרך שרתי DNS פתוחים (Amplification Attack). הגנה כוללת שימוש ב-DNSSEC לאימות קריפטוגרפי של תשובות DNS.")

# 7. TCP/IP
add("מהו TCP/IP וכיצד מתבצע חיבור TCP (Three-Way Handshake)?",
"TCP/IP היא חבילת פרוטוקולים המהווה את הבסיס לתקשורת באינטרנט. TCP (Transmission Control Protocol) מספק תקשורת אמינה ומכוונת-חיבור, בעוד IP (Internet Protocol) אחראי על ניתוב חבילות בין רשתות. חיבור TCP נפתח בתהליך Three-Way Handshake: 1) הלקוח שולח SYN, 2) השרת עונה SYN-ACK, 3) הלקוח שולח ACK - ולאחר מכן זרם הנתונים מתחיל. הבנת תהליך זה חשובה לזיהוי מתקפות כמו SYN Flood, בהן תוקף שולח כמות עצומה של בקשות SYN ללא השלמת ה-handshake, ומציף את משאבי השרת.")
add("מה ההבדל בין TCP ל-UDP?",
"TCP הוא פרוטוקול מכוון-חיבור (Connection-Oriented) המבטיח אספקת חבילות מסודרת, אמינה עם בקרת שגיאות ו-retransmission - מתאים לגלישה, אימייל והעברת קבצים. UDP הוא פרוטוקול חסר-חיבור (Connectionless) המהיר יותר אך לא מבטיח הגעה או סדר של חבילות - משמש בסטרימינג, VoIP ו-DNS. מבחינת אבטחה, UDP רגיש יותר למתקפות Spoofing ו-Amplification (למשל NTP/DNS Amplification) כיוון שאין אימות handshake.")

# 8. Cryptography
add("מהי קריפטוגרפיה (Cryptography) ומהם סוגי ההצפנה העיקריים?",
"קריפטוגרפיה היא מדע הגנת המידע באמצעות המרתו לצורה בלתי קריאה למי שאין לו את המפתח הנכון. קיימים שני סוגים עיקריים: 1) הצפנה סימטרית (Symmetric) - אותו מפתח משמש להצפנה ולפענוח (למשל AES), מהירה אך דורשת שיתוף מפתח מאובטח. 2) הצפנה א-סימטרית (Asymmetric) - זוג מפתחות, ציבורי ופרטי (למשל RSA, ECC), פותרת את בעיית שיתוף המפתח אך איטית יותר. בפועל פרוטוקולים כמו TLS משלבים את שני הסוגים - א-סימטרי להחלפת מפתח, סימטרי להצפנת התעבורה עצמה.")
add("מהו Hashing ומה ההבדל בינו לבין הצפנה?",
"Hashing הוא תהליך חד-כיווני ההופך קלט בגודל כלשהו לפלט קבוע-אורך (Hash/Digest), כשלא ניתן להפוך את התהליך ולקבל את הקלט המקורי. בניגוד להצפנה, אין מפתח לפענוח - המטרה היא שלמות ואימות (למשל אחסון סיסמאות, בדיקת תקינות קובץ) ולא שמירת סודיות שניתן לבטל. פונקציות מומלצות לסיסמאות: bcrypt, scrypt, Argon2 (כוללות Salt ו-Work Factor). פונקציות כמו MD5 ו-SHA1 נחשבות פרוצות/חלשות ולא מומלצות עוד לשימושי אבטחה.")

# 9. OWASP Top 10
add("מהי רשימת OWASP Top 10?",
"OWASP Top 10 היא רשימה המתעדכנת מעת לעת על ידי ארגון ה-Open Web Application Security Project, ומדרגת את עשרת סיכוני האבטחה המשמעותיים ביותר באפליקציות web, על בסיס נתונים ומחקר מהתעשייה. הרשימה משמשת תקן דה-פקטו להדרכת מפתחים, לביקורות אבטחה ולתוכניות הכשרה. גרסת 2021 כוללת בין היתר: Broken Access Control, Cryptographic Failures, Injection, Insecure Design, Security Misconfiguration, Vulnerable and Outdated Components, Identification and Authentication Failures, Software and Data Integrity Failures, Security Logging and Monitoring Failures, ו-Server-Side Request Forgery (SSRF).")
add("מהי הקטגוריה 'Broken Access Control' ב-OWASP Top 10 ולמה היא מדורגת ראשונה?",
"Broken Access Control מתארת מצב שבו משתמש מסוגל לבצע פעולות או לגשת לנתונים שאינם אמורים להיות מורשים לו - למשל צפייה בנתוני משתמש אחר (IDOR), עקיפת בדיקות הרשאה בצד השרת, או הגעה ישירה ל-URL של דף מנהל. היא מדורגת ראשונה מכיוון שהיא נפוצה מאוד, קלה יחסית לניצול, וההשלכות שלה חמורות - חשיפת נתונים או השתלטות על חשבונות. ההגנה המרכזית היא אכיפת בדיקות הרשאה בצד השרת עבור כל בקשה, ולא הסתמכות על הסתרה בממשק בלבד.")
add("מהי הקטגוריה 'Injection' ב-OWASP Top 10?",
"Injection מתארת משפחת חולשות שבהן קלט לא מסונן ממשתמש נשלח כפקודה או שאילתה לפרשן (interpreter) - כמו SQL, מערכת ההפעלה או LDAP - וגורם להתנהגות לא מכוונת. הדוגמה הנפוצה ביותר היא SQL Injection, אך גם Command Injection ו-NoSQL Injection נכללים בקטגוריה. ההגנה העיקרית היא שימוש ב-Parameterized Queries/Prepared Statements, ולעולם לא לבנות שאילתות באמצעות שרשור מחרוזות עם קלט משתמש.")

# 10. CWE
add("מהו CWE (Common Weakness Enumeration)?",
"CWE הוא קטלוג מתוחזק על ידי MITRE של סוגי חולשות תוכנה וחומרה נפוצים, המסווג ומתעד דפוסי חולשה גנריים ברמת קוד/עיצוב (למשל CWE-89 עבור SQL Injection, CWE-79 עבור XSS). בניגוד ל-CVE שמתעד פגיעות ספציפית במוצר מסוים, CWE מתאר את 'סוג' הבעיה באופן כללי ומופשט, ומשמש כבסיס לסיווג, להדרכת מפתחים בכתיבת קוד מאובטח, ולכלי סטטיים לניתוח קוד (SAST).")

# 11. CVE
add("מהו CVE (Common Vulnerabilities and Exposures)?",
"CVE הוא מזהה ייחודי וסטנדרטי (בפורמט CVE-שנה-מספר, למשל CVE-2021-44228 עבור Log4Shell) הניתן לפגיעות אבטחה ספציפית שהתגלתה במוצר תוכנה או חומרה קונקרטי. המערכת מתוחזקת על ידי MITRE ומאפשרת לארגונים, לחוקרי אבטחה ולכלי סריקה לתקשר ולזהות פגיעות באופן אחיד ברחבי העולם, ולעקוב אחר תיקונים ופרסומים הקשורים אליה. לכל רשומת CVE מצורף בדרך כלל ציון חומרה לפי CVSS (Common Vulnerability Scoring System).")

# 12. MITRE ATT&CK
add("מהו MITRE ATT&CK Framework?",
"MITRE ATT&CK הוא מאגר ידע גלובלי המתעד טקטיקות (Tactics - המטרה, למשל Initial Access, Persistence, Exfiltration) וטכניקות (Techniques - השיטה הספציפית) שתוקפים אמיתיים משתמשים בהם במתקפות סייבר, בהתבסס על תצפיות מהעולם האמיתי. הפריימוורק בנוי כמטריצה ומשמש צוותי Blue Team ו-SOC לבניית זיהויים, לביצוע Threat Hunting, לתרגול Red Team/Purple Team, ולמיפוי כיסוי אבטחה ארגוני מול טכניקות תקיפה ידועות.")

# 13. Secure Coding
add("מהם עקרונות ה-Secure Coding (כתיבת קוד מאובטח)?",
"Secure Coding הוא גישה לפיתוח תוכנה השמה דגש על מניעת חולשות אבטחה כבר בשלב הכתיבה. עקרונות מרכזיים: Input Validation (אימות/סינון כל קלט חיצוני), Output Encoding (קידוד פלט למניעת XSS), Least Privilege (הרשאות מינימליות נדרשות בלבד), Defense in Depth (מספר שכבות הגנה), Fail Securely (כשל במערכת לא חושף מידע או פותח פרצה), הימנעות משרשור מחרוזות עם קלט משתמש בשאילתות, וניהול נכון של סודות (Secrets) ותצורה (Configuration) ללא Hardcoding.")

# 14. Reverse Engineering
add("מהו Reverse Engineering בהקשר של אבטחת מידע?",
"Reverse Engineering הוא תהליך של פירוק תוכנה קומפילית (בינארית) לצורך הבנת מבנה, לוגיקה או פונקציונליות שלה ללא גישה לקוד המקור. בהקשר אבטחתי משמש לניתוח נוזקות (Malware Analysis), איתור חולשות בתוכנות סגורות (Vulnerability Research), בדיקת רישיונות/הגנות אנטי-פיראטיות, ואימות שקוד מהודר תואם לכוונה המקורית. כלים נפוצים: IDA Pro, Ghidra, x64dbg, radare2. הטכניקה מתחלקת ל-Static Analysis (בדיקת הקוד ללא הרצה) ו-Dynamic Analysis (הרצת התוכנה תחת דיבאגר/סנדבוקס לצפייה בהתנהגות בזמן אמת).")

# 15. Malware Analysis
add("מהו Malware Analysis מנקודת מבט הגנתית?",
"Malware Analysis הוא תהליך חקירת קובץ או תהליך חשוד כדי להבין את מטרתו, התנהגותו והשפעתו, לצורך זיהוי, בלימה ותגובה. כולל שני שלבים עיקריים: Static Analysis - בחינת הקובץ ללא הרצה (חתימות, מחרוזות, מבנה PE/ELF, hash) כדי לזהות אינדיקטורים ידועים (IOCs); ו-Dynamic Analysis - הרצת הקובץ בסביבת סנדבוקס מבודדת (למשל Cuckoo Sandbox) כדי לצפות בשינויים במערכת הקבצים, ברישום (Registry), ובתעבורת רשת. תוצרי הניתוח משמשים לכתיבת חתימות זיהוי (YARA rules), עדכון מערכות EDR/AV, ותחקור אירוע (Incident Response).")

# 16. Cloud Security
add("מהי Cloud Security ומהם עקרונותיה המרכזיים?",
"Cloud Security הוא תחום העוסק בהגנה על נתונים, אפליקציות ותשתיות המאוחסנות בסביבות ענן (AWS, Azure, GCP). עיקרון מפתח הוא ה-Shared Responsibility Model - ספק הענן אחראי על אבטחת ה-'תשתית' (Security OF the Cloud: מרכזי נתונים, חומרה, וירטואליזציה), בעוד הלקוח אחראי על אבטחה 'בתוך' הענן (Security IN the Cloud: הגדרות IAM, הצפנת נתונים, תצורת רשתות, ניהול גישה). טעויות תצורה נפוצות כוללות S3 Buckets פתוחים לציבור, הרשאות IAM רחבות מדי (over-privileged), ומפתחות API חשופים.")

# 17. Code Review
add("מהו Code Review ומה תפקידו באבטחת מידע?",
"Code Review הוא תהליך שיטתי של בחינת קוד מקור על ידי מפתחים או אנשי אבטחה נוספים, במטרה לאתר באגים, בעיות עיצוב וחולשות אבטחה לפני שהקוד מגיע לייצור. Security Code Review מתמקד באיתור דפוסים מסוכנים כמו קלט לא מאומת, שאילתות דינמיות, ניהול הרשאות שגוי וסודות חשופים בקוד. ניתן לבצע ידנית או בעזרת כלי SAST (Static Application Security Testing) האוטומטיים כמו Semgrep, SonarQube או CodeQL, המשולבים לרוב בתהליך ה-CI/CD.")

# 18. Threat Modeling
add("מהו Threat Modeling וכיצד מבצעים אותו?",
"Threat Modeling הוא תהליך מובנה לזיהוי, ניתוח ותיעדוף איומי אבטחה פוטנציאליים על מערכת עוד בשלב התכנון, לפני כתיבת קוד. שיטה נפוצה היא STRIDE - Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege - המסייעת לסווג את סוגי האיומים האפשריים לכל רכיב במערכת. התהליך כולל בדרך כלל שרטוט Data Flow Diagram, זיהוי Trust Boundaries, מיפוי איומים לפי כל רכיב, ולבסוף קביעת בקרות מיטיגציה מתאימות.")

# 19. Authentication
add("מהי Authentication (אימות זהות) ומהן שיטותיה?",
"Authentication היא תהליך אימות זהותו של משתמש או מערכת - כלומר 'מי אתה'. שיטות נפוצות: Something you know (סיסמה, PIN), Something you have (טוקן, טלפון נייד לצורך OTP), Something you are (ביומטריה - טביעת אצבע, זיהוי פנים). Multi-Factor Authentication (MFA) משלב שתי שיטות או יותר להגברת האבטחה. חשוב להבחין בין Authentication (אימות זהות) ל-Authorization (מה מותר לך לעשות) - אלו שני שלבים נפרדים ולעיתים קרובות מבולבלים.")

# 20. JWT
add("מהו JWT (JSON Web Token) וכיצד הוא בנוי?",
"JWT הוא תקן פתוח (RFC 7519) לייצוג מוצפן/חתום של Claims (טענות) בין שני צדדים, נפוץ למימוש Authentication ו-Authorization ב-APIs. המבנה מורכב משלושה חלקים מופרדים בנקודה, מקודדים ב-Base64Url: Header (מציין אלגוריתם וסוג הטוקן), Payload (מכיל את ה-Claims כגון user ID ותוקף), ו-Signature (חתימה קריפטוגרפית לאימות שהטוקן לא שונה). חולשות נפוצות: קבלת אלגוריתם 'none' ללא בדיקה, שימוש במפתח חלש לחתימת HMAC, ואי-בדיקת תוקף (expiration) של הטוקן.")

# 21. OAuth
add("מהו OAuth 2.0 ולמה הוא משמש?",
"OAuth 2.0 הוא פרוטוקול הרשאה (Authorization) המאפשר לאפליקציית צד שלישי לקבל גישה מוגבלת למשאבי משתמש בשירות אחר, ללא צורך לחשוף את הסיסמה שלו. דוגמה נפוצה: 'התחבר עם Google'. הזרימה כוללת מספר תפקידים - Resource Owner (המשתמש), Client (האפליקציה המבקשת גישה), Authorization Server (מנפיק את ה-Token) ו-Resource Server (מארח את הנתונים). חשוב לציין ש-OAuth נועד ל-Authorization ולא ל-Authentication - לצורך אימות זהות משתמש בפועל נבנה עליו תקן נוסף בשם OpenID Connect (OIDC).")

# 22. Cookies
add("מהם Cookies וכיצד משתמשים בהם באבטחה?",
"Cookies הם פיסות מידע קטנות שהשרת שולח לדפדפן ונשמרות בו, ונשלחות חזרה בכל בקשה עוקבת לאותו דומיין - פתרון מרכזי לשמירת מצב בפרוטוקול Stateless כמו HTTP (למשל שמירת Session ID). Cookies רגישים לאבטחה כוללים דגלים חשובים: Secure (נשלח רק דרך HTTPS), HttpOnly (חוסם גישה מ-JavaScript, מונע גניבה ב-XSS), ו-SameSite (Strict/Lax/None - שולט מתי הדפדפן שולח את ה-Cookie בבקשות חוצות-אתרים, ומהווה הגנה מרכזית מפני CSRF).")

# 23. Sessions
add("מהי Session בהקשר אבטחתי וכיצד מנוהלת?",
"Session היא תקופת אינטראקציה מזוהה בין משתמש לשרת, המאפשרת לשרת 'לזכור' את המשתמש בין בקשות שונות למרות ש-HTTP הוא Stateless. בדרך כלל, לאחר התחברות מוצלח השרת מייצר Session ID אקראי וקשה לניחוש, שנשמר ב-Cookie אצל הלקוח ומקושר לנתוני המשתמש בצד השרת. סיכוני אבטחה כוללים Session Hijacking (גניבת ה-ID), Session Fixation (הכפייה על משתמש להשתמש ב-Session ID ידוע מראש), ולכן חשוב לחדש (regenerate) Session ID לאחר login, להגביל תוקף (timeout) ולבטל Sessions בעת logout.")

# 24. CORS
add("מהו CORS (Cross-Origin Resource Sharing)?",
"CORS הוא מנגנון דפדפן המבוסס על HTTP Headers, המאפשר לשרת להצהיר אילו מקורות (Origins) חיצוניים מורשים לבצע בקשות ולקרוא תגובות ממנו, כחריגה מבוקרת למדיניות ברירת המחדל Same-Origin Policy. השרת מגדיר Headers כמו Access-Control-Allow-Origin לציון מקורות מותרים. תצורה שגויה - כמו הגדרת Access-Control-Allow-Origin: * יחד עם Access-Control-Allow-Credentials: true - מהווה חולשת אבטחה חמורה המאפשרת לאתר זדוני לקרוא נתונים רגישים של משתמש מחובר מאתר אחר.")

# 25. CSP
add("מהו CSP (Content Security Policy)?",
"CSP הוא Header אבטחה שהשרת שולח לדפדפן, המגדיר מדיניות מחמירה לגבי אילו מקורות תוכן (סקריפטים, סגנונות, תמונות וכו') מותר לטעון ולהריץ בדף. הוא מהווה שכבת הגנה משמעותית (Defense in Depth) מפני מתקפות XSS, כיוון שגם אם תוקף מצליח להזריק קוד, אם ה-CSP לא מתיר הרצת inline scripts ממקורות לא מורשים, הקוד הזדוני לא ירוץ. דוגמה: Content-Security-Policy: default-src 'self'; script-src 'self' https://trusted-cdn.com מתירה טעינת סקריפטים רק מהדומיין עצמו ומ-CDN מוגדר.")

# 26. XSS
add("מהי חולשת XSS (Cross-Site Scripting)?",
"XSS היא חולשה המאפשרת לתוקף להזריק קוד JavaScript זדוני לדף שנצפה על ידי משתמשים אחרים, שרץ בהקשר (context) של האתר הלגיטימי בדפדפן הקורבן. השלכות אפשריות: גניבת Cookies/Session, הפניה לאתרי דיוג, שינוי תוכן העמוד (Defacement) וביצוע פעולות בשם המשתמש. קיימים שלושה סוגים עיקריים: Stored XSS (הקוד הזדוני נשמר בשרת, למשל בתגובת בלוג, ונטען לכל מבקר), Reflected XSS (הקוד מוזרק דרך פרמטר ב-URL וחוזר מיידית בתגובה), ו-DOM-based XSS (הפגיעות נוצרת אך ורק בצד הלקוח דרך מניפולציה של ה-DOM ב-JavaScript, ללא מעורבות השרת).")
add("כיצד מונעים XSS בפיתוח אפליקציית web?",
"ההגנה העיקרית מפני XSS היא Output Encoding - קידוד כל קלט משתמש בהתאם להקשר שבו הוא מוצג (HTML, Attribute, JavaScript, URL) לפני הצגתו בדף, כך שתווים מיוחדים כמו < ו-> לא יתפרשו כקוד. בנוסף מומלץ: אימות קלט (Input Validation) לפי Whitelist, שימוש בפריימוורקים מודרניים (React, Angular) שמבצעים Escaping אוטומטי כברירת מחדל, הגדרת Content Security Policy, וסימון Cookies רגישים כ-HttpOnly כדי להגביל את הנזק גם אם XSS מתרחש.")

# 27. SQL Injection
add("מהי חולשת SQL Injection וכיצד היא עובדת?",
"SQL Injection היא חולשה המתרחשת כאשר קלט משתמש משולב ישירות בשאילתת SQL ללא סינון או פרמטריזציה, ומאפשרת לתוקף לשנות את מבנה השאילתה המקורית. לדוגמה, שאילתת התחברות פשוטה SELECT * FROM users WHERE username='$user' AND password='$pass' ניתנת לעקיפה על ידי הזנת ' OR '1'='1 בשדה שם המשתמש, מה שהופך את התנאי לאמת תמיד. השלכות אפשריות: עקיפת אימות, חילוץ נתונים רגישים מכל בסיס הנתונים, שינוי או מחיקת נתונים, ובמקרים מסוימים אף הרצת פקודות מערכת הפעלה.")
add("כיצד מונעים SQL Injection?",
"ההגנה המרכזית והיעילה ביותר היא שימוש ב-Parameterized Queries (Prepared Statements), שבהם קלט המשתמש מועבר כפרמטר נפרד ולא משורשר לתוך מחרוזת השאילתה, כך שהפרשן (parser) של בסיס הנתונים אינו יכול לפרש אותו כקוד SQL. הגנות נוספות: שימוש ב-ORM מאובטח, אימות והגבלת קלט (Input Validation), עקרון הרשאות מינימליות עבור משתמש בסיס הנתונים (Least Privilege), והימנעות מוחלטת משרשור מחרוזות דינמי עם קלט לא מהימן.")

# 28. CSRF
add("מהי חולשת CSRF (Cross-Site Request Forgery)?",
"CSRF היא מתקפה שבה תוקף מערים על משתמש מחובר (מאומת) לבצע פעולה לא רצויה באתר אחר בלי ידיעתו, על ידי ניצול העובדה שהדפדפן שולח אוטומטית Cookies רלוונטיים לכל בקשה, כולל בקשות שהוגשו מאתר זדוני חיצוני. לדוגמה, תג <img> או טופס נסתר באתר זדוני שמגיש בקשת POST להעברת כספים בבנק - אם המשתמש מחובר לבנק, הבקשה תתבצע בהרשאותיו ללא ידיעתו. הגנה עיקרית: שימוש ב-CSRF Tokens ייחודיים לכל Session/טופס, בדיקת Header ה-Origin/Referer, והגדרת Cookies עם SameSite=Strict/Lax.")

# 29. SSRF
add("מהי חולשת SSRF (Server-Side Request Forgery)?",
"SSRF היא חולשה המאפשרת לתוקף לגרום לשרת לשלוח בקשות HTTP למקום שהתוקף בוחר, כאשר האפליקציה מבצעת בקשה יוצאת המבוססת על קלט משתמש (למשל שדה 'הזן URL לתמונה'). תוקף יכול לנצל זאת כדי לגשת למשאבים פנימיים שאינם חשופים לאינטרנט - כמו שירותי מטא-דאטה בענן (169.254.169.254 ב-AWS, שעלול לחשוף credentials), שרתים פנימיים ב-Localhost, או לסרוק את הרשת הפנימית (Port Scanning). הגנה: אימות/Whitelist קפדני של כתובות URL ודומיינים מותרים, וחסימת גישה לכתובות פנימיות (Private IP ranges) ברמת הרשת.")

# 30. IDOR
add("מהי חולשת IDOR (Insecure Direct Object Reference)?",
"IDOR היא חולשה מסוג Broken Access Control, המתרחשת כאשר אפליקציה חושפת הפניה ישירה לאובייקט פנימי (כמו מזהה רשומה ב-URL, למשל /invoice?id=1005) מבלי לבדוק בצד השרת האם למשתמש המבקש יש הרשאה לגשת לאותו אובייקט ספציפית. תוקף יכול פשוט לשנות את המזהה (למשל ל-1006) ולגשת לנתונים של משתמש אחר. הגנה: אכיפת בדיקת הרשאה (Authorization Check) בצד השרת עבור כל בקשה לפי המשתמש המחובר בפועל, ולא הסתמכות על 'הסתרת' המזהה בלבד, וכן שימוש במזהים לא ניתנים לניחוש (UUID) כשכבת הגנה נוספת.")

# 31. RCE
add("מהי חולשת RCE (Remote Code Execution)?",
"RCE היא אחת מהחולשות החמורות ביותר, המאפשרת לתוקף להריץ קוד שרירותי על שרת יעד מרחוק, ולעיתים קרובות להשתלט עליו במלואו. חולשות RCE נובעות ממגוון סיבות: deserialization לא מאובטח של נתונים לא מהימנים, חולשות בספריות/רכיבים עם קוד ותיק (כמו Log4Shell - CVE-2021-44228), Command Injection, או Upload של קבצים זדוניים המתפרשים כקוד. הגנה כוללת עדכון שוטף של תלויות, Input Validation קפדני, הרצת שירותים בהרשאות מינימליות (Sandboxing/Containers), ו-Web Application Firewall (WAF).")

# 32. Command Injection
add("מהי חולשת Command Injection?",
"Command Injection מתרחשת כאשר אפליקציה מעבירה קלט משתמש לפונקציה המריצה פקודות מערכת הפעלה (כמו system(), exec() ב-PHP/Python) ללא סינון מתאים, ומאפשרת לתוקף לצרף פקודות נוספות באמצעות תווי הפרדה כמו ; או && או |. לדוגמה, אם אפליקציה מריצה ping $ip_address ותוקף מזין 8.8.8.8; cat /etc/passwd, שתי הפקודות ירוצו. הגנה: הימנעות מוחלטת מקריאה לפקודות מערכת עם קלט משתמש כשניתן, ואם הכרחי - שימוש ב-Whitelist קפדני של תווים מותרים ופונקציות המפרידות בין הפקודה לפרמטרים (כמו execve עם מערך ארגומנטים במקום shell string).")

# 33. File Upload Security
add("מהם עקרונות האבטחה בהעלאת קבצים (File Upload Security)?",
"תכונת העלאת קבצים היא וקטור תקיפה נפוץ המאפשר, אם לא מאובטח כראוי, העלאת קובץ זדוני (למשל web shell) שהתוקף יוכל להריץ מרחוק. עקרונות הגנה: אימות סוג הקובץ לפי תוכן (Magic Bytes) ולא רק לפי סיומת/Content-Type שניתנים לזיוף בקלות; הגבלת סוגי קבצים מותרים ל-Whitelist מצומצם; שינוי שם הקובץ לשם אקראי ומניעת path traversal; אחסון קבצים שהועלו מחוץ ל-Web Root או בשירות אחסון נפרד (כמו S3) ללא הרשאת הרצה; והגבלת גודל קובץ מקסימלי למניעת DoS.")

# 34. API Security
add("מהם עקרונות ה-API Security?",
"API Security עוסק בהגנה על ממשקי תכנות שחושפים נתונים ופונקציונליות בין מערכות. עקרונות מרכזיים כוללים: Authentication ו-Authorization חזקים לכל endpoint (למשל OAuth2/JWT), Rate Limiting למניעת שימוש לרעה ו-Brute Force, Input Validation קפדני על כל פרמטר, הימנעות מחשיפת מידע עודף בתגובות (Excessive Data Exposure), ו-API Versioning מבוקר. פרויקט OWASP מפרסם רשימת OWASP API Security Top 10 נפרדת, הכוללת בין היתר Broken Object Level Authorization (BOLA - למעשה IDOR ב-API) כסיכון המוביל.")

# 35. Docker Security
add("מהם עקרונות האבטחה בעבודה עם Docker (Docker Security)?",
"Docker Security עוסק בהגנה על מכולות (Containers) לאורך מחזור החיים שלהן. עקרונות מרכזיים: שימוש ב-Base Images רשמיות ומעודכנות ותוך סריקת חולשות (image scanning עם כלים כמו Trivy); הימנעות מהרצת תהליכים בתוך המכולה כמשתמש root; אי-חשיפת ה-Docker Socket (/var/run/docker.sock) פנימה למכולות שאינן מהימנות, מכיוון שגישה אליו שקולה להרשאות root על ה-Host; שימוש ב-Multi-stage builds לצמצום שטח התקיפה; והימנעות מהטמעת Secrets (סיסמאות, מפתחות) בתוך שכבות ה-Image.")

# 36. Kubernetes Security
add("מהם עקרונות האבטחה ב-Kubernetes (Kubernetes Security)?",
"Kubernetes Security כולל הגנה על אשכול (Cluster) הרצת מכולות בקנה מידה. עקרונות מרכזיים: RBAC (Role-Based Access Control) להגבלת הרשאות משתמשים ו-Service Accounts לפי עקרון הרשאות מינימליות; Network Policies להגבלת תקשורת בין Pods; שימוש ב-Secrets Management (למשל Vault) במקום ConfigMaps רגילים לנתונים רגישים; הגדרת Pod Security Standards/Admission Controllers למניעת הרצת Pods בהרשאות מוגזמות (Privileged); ועדכון שוטף של גרסת ה-Cluster וסריקת Manifests ל-misconfigurations.")

# 37. GitHub Security
add("מהם עקרונות אבטחה ב-GitHub (GitHub Security)?",
"GitHub Security כולל שורה של פרקטיקות להגנה על מאגרי קוד. עקרונות מרכזיים: אימות דו-שלבי (2FA) לכל חשבון, שימוש ב-Branch Protection Rules הדורשות Code Review לפני מיזוג, סריקת Secrets אוטומטית (GitHub Secret Scanning) לזיהוי מפתחות API שהודלפו בטעות להיסטוריית ה-commits, שימוש ב-Dependabot לאיתור ועדכון תלויות עם חולשות ידועות, וכן חתימת commits (GPG/SSH signing) לאימות זהות המחבר. יש להימנע לחלוטין מהעלאת קבצי סודות (.env, מפתחות פרטיים) למאגר, גם אם המאגר פרטי.")

# 38. CI/CD Security
add("מהם עקרונות אבטחה בתהליכי CI/CD?",
"CI/CD Security עוסק בהגנה על צנרת הבנייה והפריסה האוטומטית של תוכנה. עקרונות מרכזיים: שילוב סריקות אבטחה אוטומטיות בכל שלב (SAST לניתוח קוד, SCA לבדיקת תלויות פגיעות, DAST לבדיקת האפליקציה הרצה) - גישת 'Shift Left' המזהה בעיות מוקדם ככל האפשר; ניהול הרשאות מוגבל ל-Pipeline Runners; אחסון Secrets בכספת ייעודית (Vault, GitHub Secrets) ולא כטקסט גלוי בקובצי התצורה; וחתימה ואימות של Artifacts (Supply Chain Security) כדי למנוע הזרקת קוד זדוני בשרשרת האספקה.")

# 39. Secrets Management
add("מהו Secrets Management ולמה הוא חשוב?",
"Secrets Management הוא תחום העוסק באחסון, גישה וניהול בטוח של פרטי סוד רגישים - סיסמאות, מפתחות API, אישורי הצפנה, טוקנים - לאורך מחזור החיים שלהם. עקרונות מרכזיים: איסור מוחלט על Hardcoding של סודות בקוד המקור, שימוש בכלים ייעודיים (HashiCorp Vault, AWS Secrets Manager, Azure Key Vault) המספקים אחסון מוצפן, בקרת גישה מבוססת הרשאות, ו-Rotation אוטומטי (החלפה תקופתית) של הסודות. יש לוודא גם שסודות אינם נחשפים בלוגים, במשתני סביבה גלויים, או בהיסטוריית Git.")

# 40. Rate Limiting
add("מהו Rate Limiting ולמה הוא חשוב לאבטחה?",
"Rate Limiting הוא מנגנון המגביל את מספר הבקשות שמשתמש/כתובת IP/מפתח API יכולים לבצע בפרק זמן נתון. הוא קריטי להגנה מפני מספר סוגי מתקפות: Brute Force על מנגנוני התחברות (ניחוש סיסמאות), Credential Stuffing, ניצול לרעה של API (Scraping מסיבי), ומתקפות DoS ברמת האפליקציה. מימוש נפוץ כולל Token Bucket או Sliding Window Algorithm, ולעיתים משולב עם חסימה זמנית (Cooldown) או CAPTCHA לאחר חריגה מהסף המותר.")

# 41. Logging
add("מהו Logging וכיצד תורם לאבטחת מידע?",
"Logging הוא תיעוד שיטתי של אירועים המתרחשים במערכת - התחברויות, שגיאות, שינויי הרשאה, בקשות API וכדומה. לוגים מאובטחים היטב הם קריטיים לחקירת אירועי אבטחה (Forensics), לזיהוי פעילות חשודה, ולעמידה ברגולציה. עקרונות חשובים: תיעוד אירועי אבטחה רלוונטיים (login נכשל/מוצלח, שינויי הרשאה, גישה לנתונים רגישים) מבלי לתעד מידע רגיש כמו סיסמאות בטקסט גלוי; הגנה על שלמות הלוגים מפני שינוי (Tamper-proof, למשל שליחה ל-SIEM מרוחק); וסנכרון זמן מדויק (NTP) בין מערכות כדי לאפשר קורלציה בין אירועים.")

# 42. Monitoring
add("מהו Monitoring באבטחת מידע וכיצד הוא נאכף?",
"Monitoring הוא ניטור רציף בזמן אמת (או קרוב לכך) של מערכות, רשתות ואירועי אבטחה, לצורך זיהוי מוקדם של פעילות חריגה או זדונית. נעשה שימוש בכלי SIEM (Security Information and Event Management) המרכזים לוגים ממקורות רבים ומפעילים עליהם כללי מתאם (Correlation Rules) לזיהוי דפוסי תקיפה, וכן כלי EDR/NDR לניטור נקודות קצה ותעבורת רשת. Dashboard וניטור מתמיד מאפשרים לצוות SOC לזהות ולהגיב לאיומים לפני שהם גורמים לנזק משמעותי.")

# 43. Incident Response
add("מהו Incident Response (תגובה לאירועי אבטחה)?",
"Incident Response הוא תהליך מובנה לזיהוי, בלימה, טיפול והתאוששות מאירוע אבטחה (כמו פריצה, נוזקה או דליפת מידע). מודל נפוץ (NIST) כולל שישה שלבים: Preparation (הכנה - נהלים וכלים מראש), Identification (זיהוי האירוע), Containment (בלימה - מניעת התפשטות הנזק), Eradication (הסרת הגורם הזדוני), Recovery (שיקום המערכות לפעילות תקינה) ו-Lessons Learned (הפקת לקחים ועדכון נהלים למניעת הישנות). תגובה מהירה ומאורגנת מצמצמת משמעותית את הנזק והעלות של אירוע.")

# 44. Security Auditing
add("מהי Security Auditing (ביקורת אבטחה)?",
"Security Auditing היא בדיקה שיטתית ומקיפה של מערכת, ארגון או תהליך, לצורך הערכת רמת העמידה שלו במדיניות אבטחה, בתקנים (כמו ISO 27001, PCI-DSS) וברגולציה. ביקורת כוללת בדרך כלל בחינת תצורות מערכת, הרשאות משתמשים, מדיניות סיסמאות, נהלי גיבוי, ותיעוד תהליכים - ולעיתים משולבת עם Penetration Testing כחלק מהתהליך. תוצר הביקורת הוא דוח המפרט פערים (Gaps) והמלצות לתיקון, המשמש את ההנהלה לקבלת החלטות.")

# 45. Vulnerability Assessment
add("מהו Vulnerability Assessment ומה ההבדל בינו לבין Penetration Testing?",
"Vulnerability Assessment הוא תהליך סריקה שיטתי (לרוב אוטומטי, בעזרת כלים כמו Nessus, Qualys, OpenVAS) לאיתור וסיווג חולשות ידועות במערכות, רשתות ואפליקציות, ללא ניסיון פעיל לנצל אותן. ההבדל המרכזי מ-Penetration Testing הוא שה-Pentest הולך צעד נוסף - מנסה לנצל בפועל את החולשות שנמצאו כדי להוכיח השפעה אמיתית (Proof of Concept) ולחשוף שרשראות תקיפה מורכבות. ארגונים בדרך כלל מבצעים Vulnerability Assessment בתדירות גבוהה (חודשי) ו-Penetration Testing בתדירות נמוכה יותר (שנתי) בשל העלות והמורכבות הגבוהה יותר של האחרון.")

# 46. AI Security
add("מהו AI Security ומהם סיכוני האבטחה הייחודיים למערכות בינה מלאכותית?",
"AI Security הוא תחום מתפתח העוסק בהגנה על מערכות למידת מכונה ובינה מלאכותית מפני איומים ייחודיים להם, מעבר לאבטחת אפליקציות מסורתית. סיכונים מרכזיים כוללים: Data Poisoning (הרעלת נתוני האימון כדי להטות את התנהגות המודל), Model Extraction/Theft (גניבת מודל קנייני על ידי שאילתות חוזרות), Adversarial Examples (קלטים מהונדסים המטעים את המודל לסיווג שגוי), Prompt Injection (ראו הרחבה בהמשך), ודליפת מידע רגיש מנתוני האימון (Membership Inference/Data Leakage). ארגון OWASP פרסם רשימת OWASP Top 10 for LLM Applications המתמקדת בסיכונים אלו.")

# 47. Prompt Injection
add("מהי חולשת Prompt Injection במערכות מבוססות LLM?",
"Prompt Injection היא חולשת אבטחה הייחודית למודלי שפה גדולים (LLM), שבה תוקף מנסח קלט (Prompt) שמטרתו לשנות, לעקוף או לבטל את ההנחיות המקוריות שהוגדרו למודל על ידי מפתחי המערכת (System Prompt), על מנת לגרום למודל לבצע פעולות לא מכוונות - כמו חשיפת מידע חסוי, עקיפת מגבלות תוכן, או הרצת פעולות לא מורשות דרך כלים המחוברים למודל (Agents/Tool Use). קיימים שני סוגים: Direct Prompt Injection (התוקף הוא המשתמש עצמו הכותב הנחיה מניפולטיבית ישירות) ו-Indirect Prompt Injection (ההנחיה הזדונית מוטמעת בתוכן חיצוני שהמודל קורא, כמו דף אינטרנט, אימייל או מסמך, ומופעלת כשהמודל מעבד אותו).")
add("כיצד ניתן להתגונן מפני Prompt Injection?",
"התגוננות מלאה מפני Prompt Injection נותרת אתגר פתוח בתעשייה ואין פתרון הרמטי יחיד, אך גישות מקובלות כוללות: הפרדה ברורה בין הנחיות המערכת לתוכן חיצוני לא מהימן (Delimiters, תיוג מקור), עקרון הרשאות מינימליות עבור כל כלי (Tool) שה-Agent יכול להפעיל, דרישת אישור אנושי (Human-in-the-loop) לפעולות רגישות או בלתי הפיכות, ניטור ורישום (Logging) של פלטי המודל לזיהוי חריגות, ושימוש במסננים/מודלים ייעודיים לזיהוי ניסיונות הזרקה בקלט לפני העברתו למודל הראשי.")

